def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    if n == 1:
        return 1
    if is_prime(n):
        return n
    if is_prime(n // 2):
        return n // 2
    if is_prime(n // 3):
        return n // 3
    if is_prime(n // 2 + 1):
        return n // 2 + 1
    else:
        for i in range(n // 2, 2, -1):
            if not (n % i):
                return i
    return 2

def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    if n == 1:
        return 1
    if is_prime(n):
        return n
    else:
        i = 2
        while i * i <= n:
            if n % i:
                i += 1
            else:
                n //= i
        return n

